#define REC_LENGTH 49
#define LATITUDE_POS 28
#define OPEN 10000

__kernel void calc_distances(__global const char* sandbox,
                             __global float* z,
                             float target_lat,
                             float target_long,
                             int rec_count) {
    int i = get_global_id(0);
    if(i < rec_count) {
        const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        // Parse latitude and longitude from record string
        char lat_str[10], long_str[10];
        int pos = 0;
        for(int j = 0; j < 5 && (LATITUDE_POS - 1 + j) < (i * REC_LENGTH + REC_LENGTH); j++) {
            lat_str[j] = rec_iter[j];
        }
        lat_str[5] = '\0';

        for(int j = 0; j < 5; j++) {
            long_str[j] = rec_iter[5 + j];
        }
        long_str[5] = '\0';

        tmp_lat = atof(lat_str);
        tmp_long = atof(long_str);

        z[i] = sqrt((tmp_lat - target_lat) * (tmp_lat - target_lat) +
                    (tmp_long - target_long) * (tmp_long - target_long));
    }
}
